@import '../../utils/choice-list.css';

:host {
  display: block;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

:host(:hover),
:host(:focus-within),
:host(.conversation-list-item--actions-open) {
  position: relative;
  z-index: var(--dimension-z-index-floating);
}

.conversation-list-item__row {
  position: relative;
  isolation: isolate;
}

.conversation-list-item {
  color: var(--color-foreground-primary);
}

.conversation-list-item--error {
  --ds-interaction-border-width: var(--dimension-stroke-width-012);
  --ds-interaction-border-color: var(--color-border-bold-negative);
}

.conversation-list-item__leading:empty,
.conversation-list-item__trailing:empty {
  display: none;
}

.conversation-list-item__leading,
.conversation-list-item__trailing,
.conversation-list-item__preview-row {
  display: flex;
  align-items: center;
}

.conversation-list-item__leading {
  align-self: center;
  width: auto;
  height: auto;
  margin-inline-start: var(--ds-control-label-inset, var(--dimension-space-025));
  margin-inline-end: var(--dimension-space-050);
}

.conversation-list-item__content {
  min-width: 0;
}

.conversation-list-item__title-row {
  display: flex;
  align-items: center;
  min-width: 0;
}

.conversation-list-item__preview-row {
  min-width: 0;
  gap: var(--dimension-space-050);
}

ds-text.conversation-list-item__title,
ds-text.conversation-list-item__preview {
  display: block;
  min-width: 0;
}

ds-text.conversation-list-item__title {
  flex: 1;
}

.conversation-list-item__unread {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: var(--dimension-size-200);
  margin-inline-end: var(--dimension-space-025);
}

ds-text.conversation-list-item__preview.ds-choice-item__subtext {
  -webkit-line-clamp: 1;
}

.conversation-list-item__actions {
  position: absolute;
  top: 50%;
  right: var(--dimension-space-100);
  z-index: var(--dimension-z-index-floating);
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--dimension-radius-half);
  background: var(--color-background-transparent);
  box-shadow: var(--effect-elevation-elevated-md);
  -webkit-backdrop-filter: blur(var(--effect-blur-sm));
  backdrop-filter: blur(var(--effect-blur-sm));
  opacity: 0;
  pointer-events: none;
  transform: translateY(-50%);
}

.conversation-list-item__row:hover .conversation-list-item__actions,
.conversation-list-item__row:has(:focus-visible) .conversation-list-item__actions,
:host(.conversation-list-item--actions-open) .conversation-list-item__actions {
  opacity: 1;
  pointer-events: auto;
}

/* Keep the row wash continuous while the pointer moves onto its sibling action. */
.conversation-list-item__row:hover .conversation-list-item::after {
  background: var(--ds-interaction-hover);
}

:host(.conversation-list-item--actions-open) .conversation-list-item::after {
  background: var(--ds-interaction-hover);
}

.conversation-list-item__row:active .conversation-list-item::after {
  background: var(--ds-interaction-pressed);
}

@media (hover: none) {
  .conversation-list-item__actions {
    opacity: 1;
    pointer-events: auto;
  }

  :host(.conversation-list-item--has-actions) .conversation-list-item__title-row {
    padding-inline-end: var(--dimension-size-400);
  }
}

.conversation-list-item__time {
  position: absolute;
  width: var(--dimension-size-050);
  height: var(--dimension-size-050);
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
}

import { Component, Element, Event, EventEmitter, h, Host, Prop } from '@stencil/core';
import type { ConversationItemState } from '../conversation-types';

@Component({
  tag: 'ds-conversation-list-item',
  styleUrl: 'ConversationListItem.css',
  scoped: true,
})
export class ConversationListItem {
  @Element() el!: HTMLElement;

  @Prop() conversationId: string = '';
  /** Visible conversation title. Named to avoid the native HTMLElement.title contract. */
  @Prop() conversationTitle: string = '';
  @Prop() preview: string = '';
  /** ISO timestamp for semantic activity metadata. */
  @Prop() updatedAt: string = '';
  @Prop() selected: boolean = false;
  @Prop() state: ConversationItemState = 'default';
  @Prop() statusLabel: string = '';
  @Prop() unreadCount: number = 0;
  /** Keep the contextual-actions surface visible while its popup is open or closing. */
  @Prop({ reflect: true }) actionsOpen: boolean = false;

  @Event() dsSelect!: EventEmitter<{ id: string }>;

  private handleClick = () => this.dsSelect.emit({ id: this.conversationId });

  private handleActionsSlotChange = (event: Event) => {
    const slot = event.target as HTMLSlotElement;
    this.el.classList.toggle(
      'conversation-list-item--has-actions',
      slot.assignedElements({ flatten: true }).length > 0
    );
  };

  render() {
    const busy = this.state === 'busy';
    const subtext = busy && this.statusLabel ? this.statusLabel : this.preview;
    const accessibleName = [
      this.conversationTitle,
      subtext,
      this.unreadCount > 0 ? `${this.unreadCount} unread` : '',
    ]
      .filter(Boolean)
      .join('. ');

    return (
      <Host
        role="listitem"
        class={{ 'conversation-list-item--actions-open': this.actionsOpen }}
      >
        <div class="conversation-list-item__row">
          <button
            type="button"
            class={{
              'conversation-list-item': true,
              'ds-choice-item': true,
              'ds-control--md': true,
              'ds-focus-ring-inset': true,
              'ds-interaction-fill': true,
              'ds-interaction-fill--selected': this.selected,
              'conversation-list-item--error': this.state === 'error',
            }}
            aria-label={accessibleName}
            aria-current={this.selected ? 'true' : undefined}
            aria-busy={busy ? 'true' : undefined}
            onClick={this.handleClick}
          >
            <span class="conversation-list-item__leading ds-choice-item__icon ds-interaction-fill__content">
              <slot name="leading" />
            </span>
            <span class="conversation-list-item__content ds-choice-item__content ds-interaction-fill__content">
              <span class="conversation-list-item__title-row">
                <ds-text
                  class="conversation-list-item__title ds-choice-item__label"
                  as="span"
                  variant="text-body-medium"
                  emphasis={this.unreadCount > 0}
                  color={this.unreadCount > 0 ? 'primary' : 'secondary'}
                  lineTruncation={1}
                >
                  {this.conversationTitle}
                </ds-text>
                {this.unreadCount > 0 ? (
                  <span class="conversation-list-item__unread">
                    <ds-badge variant="dot" surface="secondary" />
                  </span>
                ) : null}
              </span>
              <span class="conversation-list-item__preview-row">
                {busy ? <ds-loader size="sm" color="secondary" /> : null}
                <ds-text
                  class="conversation-list-item__preview ds-choice-item__subtext"
                  as="span"
                  variant="text-body-small"
                  color={this.state === 'error' ? 'negative' : 'secondary'}
                  lineTruncation={1}
                >
                  {subtext}
                </ds-text>
              </span>
              {this.updatedAt ? (
                <time class="conversation-list-item__time" dateTime={this.updatedAt}>
                  {this.updatedAt}
                </time>
              ) : null}
            </span>
            <span class="conversation-list-item__trailing ds-interaction-fill__content">
              <slot name="trailing" />
            </span>
          </button>
          <div class="conversation-list-item__actions">
            <slot name="actions" onSlotchange={this.handleActionsSlotChange} />
          </div>
        </div>
      </Host>
    );
  }
}
